function feedbackBaseUrl() {
  return `https://github.com/${FEEDBACK_REPOSITORY}/issues/new`;
}

function activePrototypeUrl() {
  if (typeof window === "undefined") return "/app";
  return window.location.href || `${window.location.origin}/app`;
}

function buildFeedbackUrl(kind = "bug") {
  const issueType = kind === "feature" ? "feature_request" : "bug_report";
  const moduleName = moduleLabel(state.module);
  const note = state.notes.find((item) => item.id === state.selectedFileId);
  const titlePrefix = kind === "feature" ? "[建议]" : "[反馈]";
  const title = `${titlePrefix} ${moduleName}：`;
  const bodyLines = [
    "## 背景",
    "",
    "请描述你遇到的问题或建议改进的体验。",
    "",
    "## 当前环境",
    `- 版本：${APP_VERSION}`,
    `- 模块：${moduleName}`,
    `- 页面：${activePrototypeUrl()}`,
    `- 当前笔记：${note?.title || "未选中"}`,
    "",
    "## 补充信息",
    "- 预期发生什么：",
    "- 实际发生什么：",
    "- 复现步骤："
  ];
  const url = new URL(feedbackBaseUrl());
  url.searchParams.set("template", `${issueType}.md`);
  url.searchParams.set("title", title);
  url.searchParams.set("body", bodyLines.join("\n"));
  return url.toString();
}

function buildFeedbackDiagnosticText() {
  const note = state.notes.find((item) => item.id === state.selectedFileId);
  const folder = folderById(state, state.selectedFolderId);
  const lines = [
    "# Yansilu Feedback Diagnostics",
    `capturedAt: ${new Date().toISOString()}`,
    `repository: ${FEEDBACK_REPOSITORY}`,
    `appVersion: ${APP_VERSION}`,
    `module: ${moduleLabel(state.module)}`,
    `page: ${activePrototypeUrl()}`,
    `selectedFolder: ${folder?.name || state.selectedFolderId || "未选中"}`,
    `selectedNote: ${note?.title || "未选中"}`,
    `userAgent: ${typeof navigator !== "undefined" ? navigator.userAgent || "unknown" : "unknown"}`
  ];
  return lines.join("\n");
}

async function openFeedbackUrl(url = "") {
  const result = await desktopCommands.openExternalUrl(url);
  return Boolean(result?.ok);
}

function generatedOriginalNoteIdFromBody(body = "") {
  const match = String(body || "").match(GENERATED_ORIGINAL_MARKER_PATTERN);
  return String(match?.[1] || "").trim();
}

function stripGeneratedOriginalMarker(body = "") {
  return String(body || "")
    .replace(/\n?<!--\s*yansilu:generated-original=[^\s>]+\s*-->\s*\n?/gi, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trimEnd();
}

function withGeneratedOriginalMarker(body = "", originalNoteId = "") {
  const cleanId = String(originalNoteId || "").trim();
  const base = stripGeneratedOriginalMarker(body);
  if (!cleanId) return base;
  const separator = base.trim() ? "\n\n" : "";
  return `${base}${separator}<!-- yansilu:generated-original=${cleanId} -->`;
}

function withGeneratedOriginalReference(body = "", originalTitle = "") {
  const cleanTitle = String(originalTitle || "").trim();
  const base = stripGeneratedOriginalMarker(body);
  if (!cleanTitle) return base;
  const visibleLink = `[[${cleanTitle}]]`;
  const visibleLine = `关联永久笔记：${visibleLink}`;
  if (base.includes(visibleLine)) return base;
  const separator = base.trim() ? "\n\n" : "";
  return `${base}${separator}${visibleLine}`;
}

function noteGeneratedOriginalNoteId(note = null) {
  return String(
    note?.generatedOriginalNoteId ||
      note?.generated_original_note_id ||
      generatedOriginalNoteIdFromBody(note?.body || "")
  ).trim();
}

function noteHasGeneratedOriginal(note = null) {
  return Boolean(noteGeneratedOriginalNoteId(note));
}

function isPersistableRelationNetworkStatus(status = "") {
  const normalized = String(status || "").trim().toLowerCase();
  return normalized === "connected" || normalized === "isolated";
}

function relationNetworkStatusForNote(note = null, options = {}) {
  const noteType = String((note?.folderId ? typeFromFolder(state, note.folderId) : "") || note?.noteType || "").trim().toLowerCase();
  const permanentLike = noteType === "permanent" || noteType === "original";
  const connectedIds = options.connectedIds instanceof Set
    ? options.connectedIds
    : state.graphConnectedNoteIds instanceof Set
      ? state.graphConnectedNoteIds
      : null;
  const connectivityReady = options.connectivityReady === undefined ? state.graphConnectivityReady === true : options.connectivityReady === true;
  if (permanentLike && connectivityReady && connectedIds) return connectedIds.has(note?.id) ? "connected" : "isolated";
  const explicitStatus = String(note?.relationNetworkStatus || note?.relation_network_status || "").trim().toLowerCase();
  if (explicitStatus === "connected" || explicitStatus === "isolated") return explicitStatus;
  const storedStatus = readStoredRelationNetworkStatus(note?.id);
  if (storedStatus === "connected" || storedStatus === "isolated") return storedStatus;
  if (!permanentLike) return "";
  if (!connectivityReady || !connectedIds) return "unknown";
  return connectedIds.has(note?.id) ? "connected" : "isolated";
}

function syncNoteRelationNetworkStatus(note = null, options = {}) {
  if (!note || typeof note !== "object") return "";
  const nextStatus = relationNetworkStatusForNote(note, options);
  note.relationNetworkStatus = nextStatus;
  const noteType = String((note?.folderId ? typeFromFolder(state, note.folderId) : "") || note?.noteType || "").trim().toLowerCase();
  if (noteType === "permanent" || noteType === "original") {
    if (isPersistableRelationNetworkStatus(nextStatus)) writeStoredRelationNetworkStatus(note.id, nextStatus);
  }
  else writeStoredRelationNetworkStatus(note.id, "");
  return nextStatus;
}

function syncAllNoteRelationNetworkStatuses(options = {}) {
  for (const note of state.notes) syncNoteRelationNetworkStatus(note, options);
}

function isOriginalRecordableSource(note = null) {
  const noteType = String((note?.folderId ? typeFromFolder(state, note.folderId) : "") || note?.noteType || "").trim().toLowerCase();
  return noteType === "fleeting" || noteType === "literature";
}

function setStatus(text, cls = "", options = {}) {
  const requiredRevision = Number(options?.skipIfStaleSince || 0);
  if (requiredRevision && statusRevision !== requiredRevision) return false;
  const requiredModule = String(options?.requireModule || "").trim();
  if (requiredModule && state.module !== requiredModule) return false;
  const now = Date.now();
  const incomingTone = String(cls || "").trim().toLowerCase();
  const incomingPriority = Math.max(
    Number(options?.priority || 0) || 0,
    incomingTone === "bad" ? 4 : incomingTone === "warn" ? 3 : 0
  );
  const force = options?.force === true;
  if (!force && now < statusHoldUntil && incomingPriority < statusHoldPriority) return false;
  statusRevision += 1;
  $("statusText").className = `status-pill ${cls}`.trim();
  $("statusText").textContent = text;
  const statusBar = $("statusBar");
  if (statusBar) statusBar.dataset.tone = cls || "";
  const holdMs = Math.max(0, Number(options?.holdMs || 0) || 0);
  if (holdMs > 0) {
    statusHoldUntil = now + holdMs;
    statusHoldPriority = incomingPriority;
  } else if (force || now >= statusHoldUntil || incomingPriority >= statusHoldPriority) {
    statusHoldUntil = 0;
    statusHoldPriority = 0;
  }
  return true;
}


function readStoredSystemMessages() {
  try {
    const raw = window.localStorage?.getItem(SYSTEM_MESSAGES_KEY);
    const parsed = raw ? JSON.parse(raw) : [];
    if (!Array.isArray(parsed)) return [];
    return parsed.map(normalizeSystemMessage).slice(0, SYSTEM_MESSAGES_LIMIT);
  } catch {
    return [];
  }
}

function persistSystemMessages() {
  try {
    window.localStorage?.setItem(SYSTEM_MESSAGES_KEY, JSON.stringify(systemMessages.slice(0, SYSTEM_MESSAGES_LIMIT)));
  } catch {}
}





function renderSystemMessages() {
  const list = $("systemMessageList");
  const detail = $("systemMessageDetail");
  const button = $("systemMessagesButton");
  const markReadButton = $("btnSystemMessageMarkRead");
  const unreadCount = systemMessages.filter((item) => item.read !== true).length;
  button?.classList.toggle("has-unread", unreadCount > 0);
  if (button) {
    const systemMessageLabel = "系统消息与 AI 建议";
    button.title = unreadCount ? `${systemMessageLabel}（${unreadCount} 条未读）` : systemMessageLabel;
    button.dataset.tip = unreadCount ? `系统消息 ${unreadCount}` : "系统消息";
    button.setAttribute("aria-label", unreadCount ? `${systemMessageLabel}，${unreadCount} 条未读` : systemMessageLabel);
  }
  if (markReadButton) {
    markReadButton.disabled = unreadCount === 0;
    markReadButton.title = unreadCount === 0 ? "没有未读系统消息" : "全部标记已读";
  }
  if (!list) return;
  if (!systemMessages.length) {
    list.innerHTML = `<div class="system-message-empty-list">暂无消息</div>`;
    if (detail) {
      detail.innerHTML = `
        <article class="system-message-detail-card system-message-empty-card">
          <h3>暂无需要处理的消息</h3>
          <div class="system-message-body">AI 分析、图谱扫描或计划任务产生待审内容后，会显示在这里；采纳前不会改动笔记或图谱。</div>
        </article>
      `;
    }
    return;
  }
  if (!systemMessages.some((message) => message.id === selectedSystemMessageId)) {
    selectedSystemMessageId = systemMessages[0]?.id || "";
  }
  const selectedMessage = systemMessages.find((message) => message.id === selectedSystemMessageId) || systemMessages[0];
  list.innerHTML = systemMessages
    .map((message) => {
      const selected = message.id === selectedMessage?.id;
      const subject = systemMessageSubjectText(message, state.notes);
      const preview = systemMessagePreviewText(message);
      const title = systemMessageDisplayTitle(message, state.notes);
      return `
        <article class="system-message-item${message.read ? "" : " is-unread"}${selected ? " is-selected" : ""}" data-system-message-id="${escapeHtml(message.id)}" data-system-message-select="${escapeHtml(message.id)}" role="button" tabindex="0">
          <button class="system-message-title" type="button" data-system-message-select="${escapeHtml(message.id)}" aria-current="${selected ? "true" : "false"}">
            ${message.read ? "" : `<span class="system-message-unread-dot" aria-label="未读"></span>`}
            <span>${escapeHtml(title)}</span>
          </button>
          ${subject ? `<div class="system-message-subject">${escapeHtml(subject)}</div>` : ""}
          <div class="system-message-preview">${escapeHtml(preview)}</div>
          <div class="system-message-meta">${message.artifactCount ? `${escapeHtml(String(message.artifactCount))} 条建议 · ` : ""}${escapeHtml(new Date(message.createdAt).toLocaleString())}</div>
        </article>
      `;
    })
    .join("");
  if (!detail || !selectedMessage) return;
  const actionLabel = systemMessageActionLabel(selectedMessage);
  detail.innerHTML = `
    <article class="system-message-detail-card" data-system-message-detail-id="${escapeHtml(selectedMessage.id)}">
      <div class="system-message-detail-kicker">${selectedMessage.resolvedAt ? "已完成" : selectedMessage.read ? "已读" : "未读"}</div>
      <h3>${escapeHtml(systemMessageDisplayTitle(selectedMessage, state.notes))}</h3>
      ${
        systemMessageSubjectText(selectedMessage, state.notes)
          ? `<div class="system-message-focus"><span>相关笔记</span><strong>${escapeHtml(systemMessageSubjectText(selectedMessage, state.notes))}</strong></div>`
          : ""
      }
      <div class="system-message-body">${escapeHtml(selectedMessage.body || "没有更多内容。")}</div>
      <div class="system-message-meta">${escapeHtml(new Date(selectedMessage.createdAt).toLocaleString())}</div>
      ${
        actionLabel
          ? `<div class="system-message-actions"><button class="mini-btn primary" type="button" data-system-message-action="${escapeHtml(selectedMessage.action)}" data-system-message-id="${escapeHtml(selectedMessage.id)}">${escapeHtml(actionLabel)}</button></div>`
          : ""
      }
    </article>
  `;
}

function openSystemMessages({ latestOnly = false } = {}) {
  const modal = $("systemMessageModal");
  if (!modal) return;
  const note = $("systemMessageModalNote");
  if (note) {
    note.textContent = latestOnly
      ? "有新的待确认事项，处理后仍可在这里回看。"
      : "这里汇总需要你确认的关系、问题和写作建议。";
  }
  if (latestOnly || !systemMessages.some((message) => message.id === selectedSystemMessageId)) {
    selectedSystemMessageId = systemMessages[0]?.id || "";
  }
  hideEditorHelper();
  document.body?.classList.add("system-message-modal-open");
  modal.classList.remove("hidden");
  renderSystemMessages();
}

function closeSystemMessages() {
  document.body?.classList.remove("system-message-modal-open");
  $("systemMessageModal")?.classList.add("hidden");
}

function isSystemMessageModalOpen() {
  const modal = $("systemMessageModal");
  return !!modal && !modal.classList.contains("hidden");
}

function markSystemMessagesRead() {
  systemMessages = systemMessages.map((message) => ({ ...message, read: true }));
  persistSystemMessages();
  renderSystemMessages();
}

function addSystemMessage(message = {}, { interrupt = false } = {}) {
  const normalized = normalizeSystemMessage(message);
  systemMessages = [normalized, ...systemMessages.filter((item) => item.id !== normalized.id)].slice(0, SYSTEM_MESSAGES_LIMIT);
  if (interrupt || !selectedSystemMessageId) selectedSystemMessageId = normalized.id;
  persistSystemMessages();
  renderSystemMessages();
  if (interrupt) openSystemMessages({ latestOnly: true });
  return normalized;
}

function upsertSystemMessage(message = {}, { interrupt = false, preserveRead = true } = {}) {
  const requested = normalizeSystemMessage(message);
  const existing = systemMessages.find((item) => item.id === requested.id || (requested.dedupeKey && item.dedupeKey === requested.dedupeKey));
  const reactivated = Boolean(existing?.resolvedAt && !requested.resolvedAt);
  const normalized = normalizeSystemMessage({
    ...(existing || {}),
    ...requested,
    id: existing?.id || requested.id,
    createdAt: existing?.createdAt || requested.createdAt,
    read: reactivated ? false : preserveRead && existing ? existing.read === true : requested.read === true
  });
  systemMessages = [normalized, ...systemMessages.filter((item) => item.id !== normalized.id)].slice(0, SYSTEM_MESSAGES_LIMIT);
  if (interrupt || !selectedSystemMessageId) selectedSystemMessageId = normalized.id;
  persistSystemMessages();
  renderSystemMessages();
  if (interrupt) openSystemMessages({ latestOnly: true });
  return normalized;
}

function resolveSystemMessageByDedupeKey(dedupeKey = "") {
  const cleanKey = String(dedupeKey || "").trim();
  if (!cleanKey) return null;
  const existing = systemMessages.find((item) => item.dedupeKey === cleanKey);
  if (!existing || existing.resolvedAt) return existing || null;
  const resolved = normalizeSystemMessage({
    ...existing,
    read: true,
    resolvedAt: new Date().toISOString()
  });
  systemMessages = systemMessages.map((item) => (item.id === resolved.id ? resolved : item));
  persistSystemMessages();
  renderSystemMessages();
  return resolved;
}


function scheduledTaskReviewArtifactCount(summary = {}) {
  return (Array.isArray(summary?.runs) ? summary.runs : []).reduce((total, run) => {
    const result = run?.result || {};
    const artifacts = Array.isArray(result.artifacts) ? result.artifacts.length : 0;
    const storedIds = Array.isArray(result.reviewItems?.storedArtifactIds) ? result.reviewItems.storedArtifactIds.length : 0;
    const reviewArtifacts = Array.isArray(result.reviewItems?.artifacts) ? result.reviewItems.artifacts.length : 0;
    return total + Math.max(artifacts, storedIds, reviewArtifacts);
  }, 0);
}

function readStoredBoolean(key, fallback = false) {
  try {
    const raw = window.localStorage?.getItem(String(key || ""));
    if (raw === "1") return true;
    if (raw === "0") return false;
  } catch {}
  return fallback;
}

function writeStoredBoolean(key, value) {
  try {
    window.localStorage?.setItem(String(key || ""), value ? "1" : "0");
  } catch {}
}

function readStoredText(key, fallback = "") {
  try {
    const raw = window.localStorage?.getItem(String(key || ""));
    if (raw === null || raw === undefined) return fallback;
    return String(raw);
  } catch {}
  return fallback;
}

function writeStoredText(key, value) {
  try {
    const clean = String(value ?? "");
    if (!clean) window.localStorage?.removeItem(String(key || ""));
    else window.localStorage?.setItem(String(key || ""), clean);
  } catch {}
}

